# scripts/waiver_tracker.py
# Reads prr-waivers.json and reports on open waivers approaching expiry.
# Run weekly via CI or cron. Alerts Slack if any waiver expires within 3 days.

import json, datetime, sys, os, pathlib, requests

WAIVERS_FILE = pathlib.Path("prr-waivers.json")
SLACK_WEBHOOK = os.environ.get("SLACK_WEBHOOK_URL")
WARN_DAYS = 3    # alert if expiry is within this many days

def load_waivers() -> list[dict]:
    if not WAIVERS_FILE.exists():
        return []
    return json.loads(WAIVERS_FILE.read_text())

now = datetime.datetime.now(tz=datetime.timezone.utc)
waivers = load_waivers()
open_waivers = [w for w in waivers if w["status"] in ("DRAFT", "APPROVED")]

alerts = []
for w in open_waivers:
    expiry = datetime.datetime.fromisoformat(w["expires"].replace("Z", "+00:00"))
    days_left = (expiry - now).days
    status_line = f"[{w['id']}] {w['domain']} — expires {w['expires'][:10]} ({days_left}d left)"

    if days_left < 0:
        alerts.append(f"VIOLATED: {status_line} — remediation date passed, feature must be gated")
    elif days_left <= WARN_DAYS:
        alerts.append(f"EXPIRING SOON: {status_line} — remediation must ship NOW")
    else:
        print(f"  OK: {status_line}")

if alerts:
    print("\nWAIVER ALERTS:")
    for a in alerts:
        print(f"  {a}")
    if SLACK_WEBHOOK:
        msg = "*PRR Waiver Alerts*\n" + "\n".join(f"• {a}" for a in alerts)
        requests.post(SLACK_WEBHOOK, json={"text": msg})

print(f"\n{len(open_waivers)} open waiver(s). {len(alerts)} alert(s).")
if any("VIOLATED" in a for a in alerts):
    sys.exit(1)
